import{_ as t}from"./chunks/lablededit.6MKmj5Mq.js";import{_ as r,a as o,b as a}from"./chunks/statusbar.BA8GrhQZ.js";import{_ as s}from"./chunks/trackbar.LGCXX873.js";import{_ as i,o as n,c as l,ae as c}from"./chunks/framework.C00B0EYs.js";const w=JSON.parse(`{"title":"Editor Workspace","description":"Understand the editor's main regions and interaction model.","frontmatter":{"title":"Editor Workspace","description":"Understand the editor's main regions and interaction model."},"headers":[],"relativePath":"docs/guide/editor.md","filePath":"docs/guide/editor.md"}`),d={name:"docs/guide/editor.md"};function h(g,e,p,u,m,k){return n(),l("div",null,[...e[0]||(e[0]=[c('<h1 id="editor-workspace" tabindex="-1">Editor Workspace <a class="header-anchor" href="#editor-workspace" aria-label="Permalink to &quot;Editor Workspace&quot;">​</a></h1><p>The editor workspace is the core operating environment of Motor Sound Editor. It is where you manage sound tracks, assign audio assets, and fine-tune how pitch and volume change across traction and braking behavior.</p><p><img src="'+t+'" alt="Annotated editor screen"></p><p>The workspace is divided into four main regions:</p><ol><li><strong>Toolbar</strong>: global tool-mode switching and project actions.</li><li><strong>Track Sidebar</strong>: the panel on the right for managing tracks, audio files, and track state.</li><li><strong>Main Workspace</strong>: the central chart area for curve editing and keyframe work.</li><li><strong>Status Bar</strong>: the bottom bar for real-time preview and speed/state control.</li></ol><h2 id="_1-toolbar" tabindex="-1">1. Toolbar <a class="header-anchor" href="#_1-toolbar" aria-label="Permalink to &quot;1. Toolbar&quot;">​</a></h2><p>The top toolbar contains the global controls that affect how you interact with the workspace.</p><p><img src="'+r+'" alt="Tools"></p><ul><li><strong>Tool Mode</strong> decides how you interact with curves and keyframes. <ul><li><strong>Select</strong> is the default mode for choosing keyframes.</li><li><strong>Move</strong> lets you drag the selected keyframe and change its position and value.</li><li><strong>Keyframe</strong> lets you insert a keyframe with left click or remove one quickly with right click.</li></ul></li><li><strong>Snap</strong> can be enabled temporarily by holding <code>Shift</code>. The current defaults snap speed to multiples of <code>0.5</code> and values to multiples of <code>0.2</code>.</li></ul><h2 id="_2-track-sidebar" tabindex="-1">2. Track Sidebar <a class="header-anchor" href="#_2-track-sidebar" aria-label="Permalink to &quot;2. Track Sidebar&quot;">​</a></h2><p>The sidebar combines ideas from layer management and mixing so you can organize every motor-sound track in the project.</p><p><img src="'+s+'" alt="Track sidebar"></p><ul><li><strong>Track List</strong> shows every track in the current project. Clicking a track makes it the <strong>active track</strong>, and the main chart updates to show that track&#39;s curves.</li><li><strong>Asset Assignment</strong> lets you assign or replace the local audio file used by a track.</li><li><strong>Track Controls</strong> include: <ul><li><strong>Show / Hide</strong> to control whether the track is visible in the chart.</li><li><strong>Mute</strong> to temporarily silence the track during preview.</li></ul></li></ul><h2 id="_3-main-workspace" tabindex="-1">3. Main Workspace <a class="header-anchor" href="#_3-main-workspace" aria-label="Permalink to &quot;3. Main Workspace&quot;">​</a></h2><p>This is the core area for editing dynamic sound behavior. The horizontal axis represents speed, while the vertical axis represents pitch or volume.</p><p><img src="'+o+'" alt="Workspace"></p><p>Each track keeps two independent curve environments:</p><ul><li><strong>Traction / Brake</strong> for acceleration and braking behavior.</li><li><strong>Pitch</strong> curves for playback-rate or frequency change.</li><li><strong>Volume</strong> curves for loudness change across the speed range.</li></ul><p>At the moment, the data model stores only dedicated <strong>Traction</strong> and <strong>Brake</strong> curve sets. During preview, <strong>Coasting</strong> still uses the traction-side curves.</p><h2 id="_4-status-bar" tabindex="-1">4. Status Bar <a class="header-anchor" href="#_4-status-bar" aria-label="Permalink to &quot;4. Status Bar&quot;">​</a></h2><p>The bottom bar is used for real-time preview and simulator-state control.</p><p><img src="'+a+'" alt="Status bar"></p><ul><li><strong>Play / Pause</strong> starts or stops the preview engine.</li><li><strong>State buttons</strong> switch between <strong>Traction</strong>, <strong>Coasting</strong>, and <strong>Brake</strong> so you can check how the sound transitions between train states. You can also use <code>W</code> and <code>S</code>.</li><li><strong>Current Speed</strong> controls the preview speed, making it easier to inspect curve behavior at specific points.</li></ul>',23)])])}const T=i(d,[["render",h]]);export{w as __pageData,T as default};
